scripts.memory:reset:
node --input-type=module <<'EOF'
import { readdirSync, writeFileSync } from 'fs';
const categories = ['profile','facts','preferences','principles','opinions','communication_style','private'];
categories.forEach(c => writeFileSync(`memory/${c}.md`, `# ${c.replace('_',' ').replace(/\b\w/g, l => l.toUpperCase())}\n`));
console.log('Memory reset.');
EOF

scripts.memory:backup:
node --input-type=module <<'EOF'
import { cpSync } from 'fs';
const ts = new Date().toISOString().slice(0,19).replace(/:/g,'-');
cpSync('memory', `memory_backup_${ts}`, { recursive: true });
console.log(`Backed up to memory_backup_${ts}`);
EOF
